export function buildDtsEntryHtml(alias: string, palette: string): string {
    return alias.includes('-')
        ? `<span class="line"><span style="color:#A31515;--shiki-dark:#CE9178">            '${alias}'</span><span style="color:#000000;--shiki-dark:#D4D4D4">: </span><span style="color:#A31515;--shiki-dark:#CE9178">'${palette}'</span><span style="color:#000000;--shiki-dark:#D4D4D4">;</span></span>`
        : `<span class="line"><span style="color:#001080;--shiki-dark:#9CDCFE">            ${alias}</span><span style="color:#000000;--shiki-dark:#D4D4D4">: </span><span style="color:#A31515;--shiki-dark:#CE9178">'${palette}'</span><span style="color:#000000;--shiki-dark:#D4D4D4">;</span></span>`;
}
